mysql -uroot -pJatni@752050 -D robodynamics_db -t -e "SELECT COUNT(*) AS total_questions FROM vida_path_question_bank; SELECT COUNT(*) AS total_careers FROM vida_path_future_career; SELECT section, COUNT(*) AS cnt FROM vida_path_question_bank GROUP BY section ORDER BY section; SELECT question_id, COUNT(*) c FROM vida_path_question_bank GROUP BY question_id HAVING c>1; SELECT LEFT(question_text,120) AS question_sample, COUNT(*) c FROM vida_path_question_bank GROUP BY question_text HAVING c>1 ORDER BY c DESC LIMIT 20;"
